  6	
  7	interface ValidationSummaryProps {
  8	  errors: number;
  9	  id: string;
 10	  objectCount?: number;
 11	  reconciledCondition?: StatusCondition;
 12	  style?: React.CSSProperties;
 13	  type: 'service' | 'istio';
 14	  warnings: number;
 15	}
 16	
 17	const tooltipListStyle = kialiStyle({
 18	  textAlign: 'left',
 19	  border: 0,
 20	  padding: 0,
 21	  margin: 0
 22	});
 23	
 24	const tooltipSentenceStyle = kialiStyle({
 25	  textAlign: 'center',
 26	  border: 0,
 27	  padding: 0,
 28	  margin: 0
 29	});
 30	
 31	export const ValidationSummary: React.FC<ValidationSummaryProps> = (props: ValidationSummaryProps) => {
 32	  const getTypeMessage = (count: number, type: ValidationTypes): string => {
 33	    return count > 1 ? `${count} ${type}s found` : `${count} ${type} found`;
 34	  };
 35	
 36	  const severitySummary = (): string[] => {
 37	    const issuesMessages: string[] = [];
 38	
 39	    if (props.errors > 0) {
 40	      issuesMessages.push(getTypeMessage(props.errors, ValidationTypes.Error));
 41	    }
 42	
 43	    if (props.warnings > 0) {
 44	      issuesMessages.push(getTypeMessage(props.warnings, ValidationTypes.Warning));
 45	    }
 46	
 47	    if (issuesMessages.length === 0) {
 48	      issuesMessages.push('No issues found');
 49	    }
 50	
 51	    return issuesMessages;
 52	  };
 53	
 54	  const severity = (): ValidationTypes => {
 55	    let severity = ValidationTypes.Correct;
 56	
 57	    if (props.errors > 0) {
 58	      severity = ValidationTypes.Error;
 59	    } else if (props.warnings > 0) {
 60	      severity = ValidationTypes.Warning;
 61	    }
 62	
 63	    return severity;
 64	  };
 65	
 66	  let tooltipContent: React.ReactNode = undefined;
 67	
 68	  if (props.type === 'istio') {
 69	    const tooltipNA = <Text className={tooltipSentenceStyle}>No Istio config objects found</Text>;
 70	
 71	    const tooltipNoValidationAvailable = <Text className={tooltipListStyle}>No Istio config validation available</Text>;
 72	
 73	    const tooltipSummary = (
 74	      <>
 75	        <Text style={{ textAlign: 'left', textEmphasis: 'strong' }} component={TextVariants.p}>
 76	          Istio config objects analyzed: {props.objectCount}
 77	        </Text>
 78	
 79	        <div className={tooltipListStyle}>
 80	          {severitySummary().map(cat => (
 81	            <div key={cat}>{cat}</div>
 82	          ))}
 83	        </div>
 84	
 85	        {props.reconciledCondition?.status && (
 86	          <Text style={{ textAlign: 'left', textEmphasis: 'strong' }} component={TextVariants.p}>
 87	            The object is reconciled
 88	          </Text>
 89	        )}
 90	      </>
 91	    );
 92	
 93	    // Tooltip Content for istio config validation
 94	    if (props.objectCount !== undefined) {
 95	      if (props.objectCount === 0) {
 96	        tooltipContent = tooltipNA;
 97	      } else {
 98	        tooltipContent = tooltipSummary;
 99	      }
100	    } else {
101	      tooltipContent = tooltipNoValidationAvailable;
102	    }
103	  } else {
104	    // Tooltip Content for service validation
105	    tooltipContent = (
106	      <>
107	        <Text style={{ textAlign: 'left', textEmphasis: 'strong' }} component={TextVariants.p}>
108	          Service validation result
109	        </Text>
110	
111	        <div className={tooltipListStyle}>
112	          {severitySummary().map(cat => (
113	            <div key={cat}>{cat}</div>
114	          ))}
115	        </div>
116	      </>
117	    );
118	  }
119	
120	  const tooltipBase =
121	    props.objectCount === undefined || props.objectCount > 0 ? (
122	      <Validation severity={severity()} />
123	    ) : (
124	      <div style={{ display: 'inline-block' }}>N/A</div>
125	    );
126	
127	  return (
128	    <Tooltip aria-label="Validations list" position={TooltipPosition.auto} enableFlip={true} content={tooltipContent}>
129	      {tooltipBase}
130	    </Tooltip>
131	  );
132	};

